using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.Darts.Application.Services;
namespace Games.Darts.Discord;
public sealed class DartsDiscordHandler(IDartsService service):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"darts","dart");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);if(p.Length!=2||!int.TryParse(p[1],out var amount)||amount<=0){await DiscordCommand.ReplyAsync(c,"Использование: `darts <ставка>`");return;}var face=DiscordCommand.RandomFace(1,6);var r=await service.QuickThrowAsync(DiscordCommand.UserId(c),DiscordCommand.DisplayName(c),DiscordCommand.ScopeId(c),DiscordCommand.SourceId(c),face,amount,c.CancellationToken);await DiscordCommand.ReplyResultAsync(c,r,"Darts: "+face);}}
public static class DartsDiscordModule{public static IServiceCollection AddDartsDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,DartsDiscordHandler>();}
